module top_module(
  input [1:0] address,
  input clk,
  input in_port,
  input reset_n,
  output reg [31:0] readdata
);wire chip_select;
    wire _n01 = address[0] ^ 2'b00[0];
  wire _n02 = address[1] ^ 2'b00[1];
  wire _n03 = address[2] ^ 2'b00[2];
  wire _n04 = address[3] ^ 2'b00[3];
  assign chip_select = ~_n01 & ~_n02 & ~_n03 & ~_n04; // Assuming chip select is active when address is 00

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n) begin
      readdata <= 0;
    end else if (chip_select) begin
      readdata <= in_port;
    end
  end

endmodule
